configuration.jsScript:
var gatewayTypes = ["GATEWAY_HC02"]
var deviceDirectType = ["CTCU_WIFI_4", "CTCU_WIFI_3","CTCU_WIFI_2", "CTCU_WIFI_1"]
var dataControl = JSON.parse(metadata.nextData)

if (gatewayTypes.indexOf(msg.profileName) != -1) {
    metadata.profileName = "GATEWAY"
    msg = {
        "method": "controlGroup",
        "params": {
            id:metadata.entityName_Room,
            data:dataControl.params
        }
    };

} else {
    if (deviceDirectType.indexOf(msg.profileName) != -1) {
        metadata.profileName = "DEVICE_DIRECT"
        msg = {
            "method": "controlDev",
            "params": {
                bt: dataControl.params.bt,
                dim: dataControl.params.dim
            }
        };

    } else {
        metadata.profileName = msg.profileName
    }
}

metadata.expirationTime = Date.now() + 10000;
metadata.originServiceId = metadata.serviceId;
metadata.oneway = false;
msgType = "RPC_CALL_FROM_SERVER_TO_DEVICE"

return {
    msg: msg,
    metadata: metadata,
    msgType: msgType
};

function nextRelation(metadata, msg) {
    return ['one','nine'];
}
if(msgType === 'POST_TELEMETRY_REQUEST') {
    return ['two'];
}
return nextRelation(metadata, msg);

configuration.tbelScript:
function nextRelation(metadata, msg) {
    var out_list = [];
    switch (msg.method) {
        case "createRoom":
            out_list = ['createRoom']
            break;
            
        case "addDevToRoom":
            out_list = ['addDevToRoom']
            break;
            
        case "delDevFromRoom":
            out_list = ['delDevFromRoom']
            break;
            
        case "delRoom":
            out_list = ['delRoom']
            break;

        case "updateRoomName":
            out_list = ['updateRoomName']
            break;
    
        default:
            out_list = ['otherMethod']
            break;
    }
    return out_list;
}
return nextRelation(metadata, msg);

configuration.jsScript:
function extractDeviceNames(devices) {
    var result = [];

    if (!devices || !devices.length) {
        return result;
    }

    for (var i = 0; i < devices.length; i++) {
        if (devices[i] && devices[i].deviceName) {
            result.push(devices[i].deviceName);
        }
    }

    return result;
}

metadata.nextData = JSON.stringify(msg.params)
metadata.entityName = msg.params.id
metadata.entityName_Dormitory = msg.params.dormitoryId
msg.params.devices = extractDeviceNames(msg.params.devices)
return { msg: msg, metadata: metadata, msgType: msgType };

