function convertCreateRoomToCreateScenes(params) {
    // var params = input.params;

    // STEP 1: map deviceName -> profileName
    var deviceProfileMap = {};
    for (var i = 0; i < params.devices.length; i++) {
        var d = params.devices[i];
        deviceProfileMap[d.deviceName] = d.profileName;
    }

    // STEP 2: map groupId -> device list
    var groupDeviceMap = {};
    for (var j = 0; j < params.groups.length; j++) {
        var g = params.groups[j];
        groupDeviceMap[g.id] = g.devices;
    }

    // STEP 3: build createScene messages
    var result = [];

    for (var s = 0; s < params.scenes.length; s++) {
        var scene = params.scenes[s];

        var sceneDevices = [];

        for (var k = 0; k < scene.groups.length; k++) {
            var sceneGroup = scene.groups[k];
            var deviceIds = groupDeviceMap[sceneGroup.id] || [];

            for (var m = 0; m < deviceIds.length; m++) {
                var deviceId = deviceIds[m];

                sceneDevices.push({
                    "id": deviceId,
                    "profileName": deviceProfileMap[deviceId],
                    "data": sceneGroup.data
                });
            }
        }

        result.push({
            "method": "createScene",
            "params": {
                "id": scene.id,
                "dormitoryId": params.dormitoryId,
                "room": params.id,
                "name": scene.name,
                "image": scene.image,
                "devices": sceneDevices
            }
        });
    }

    return result;
}

