function extractSceneDataKeys(input) {
    var result = [];
    var key;
    var prefix = "ss_sceneData_";
    var prefixLength = prefix.length;

    for (key in input) {
        if (input.hasOwnProperty(key) && key.indexOf(prefix) === 0) {
            result.push({
                sceneDataKey: key.substring(3) // remove "ss_"
            });
        }
    }

    return result;
}
msg = extractSceneDataKeys(msg);
return { msg: msg, metadata: metadata, msgType: msgType };

